#!/usr/bin/env bash
# 10-100.sh — 规模化：私域团队 + 多触点 + 数据归因体系（10→100） SOP walkthrough for 微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变)"
WORKFLOW="规模化：私域团队 + 多触点 + 数据归因体系（10→100）"

usage() {
  cat <<EOF
10-100.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./10-100.sh             # interactive
  ./10-100.sh --dry-run
  ./10-100.sh --json
  ./10-100.sh --explain
  ./10-100.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "规模化：私域团队 + 多触点 + 数据归因体系（10→100）" 工作流。

一句话: 私域精细化运营已跑顺后，从「一个操盘手 / 小团队靠经验跑」到「有组织分工、多触点协同、有数据归因体系的可复制规模化运营」——让私域成为公司级的、不依赖单个人的增长资产。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 公私二分 / 流量自主权（mental model）: 私域人看一切流量的底层镜片是「这部分流量是租来的还是自己的」——租来的（公域）用一次付一次、平台控分发，自己的（私域）可反复免费触达；近年这对二分从「对立」演化为「全域协同」，但「自主权」这条轴没变。
  • 流量池 / 蓄水养鱼（mental model）: 私域人把流量当成「要蓄进池子、反复经营」的对象而非「这次能转化多少」的一次性曝光——但「建了群 / 加了好友」只是蓄了水，**没有运营动作的池是死水**；价值在「蓄水—养鱼—捕鱼」的循环，不在池子大小

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**拆组织分工**：把「一个人干所有事」拆成角色——引流 / 1v1 客服(导购) / 社群运营 / 内容(朋友圈+公众号+视频号) / 数据，定 SOP 让新人可上手。who: 私域负责人。(evidence: [T03-S008])"
  "**定分层 KPI**：给每个角色 / 每个阶段定可量化指标（如引流看加粉成本与留存、客服看转化率、社群看活跃与 GMV）——「运营路径上每个关键节点都要有 SOP + 指标」。(evidence: [T03-S008])"
  "**多触点协同**：把企微 + 视频号 + 小程序 + 公众号 + 社群打通，用 UnionID 串联同一用户的多触点身份，避免一个用户在不同触点被当成多个人重复运营。(evidence: [T03-S002])"
  "**搭 GMV 归因体系**：统一私域 GMV 归因口径，把成交额归因到具体渠道 / 动作，回答「私域贡献了多少、哪一环有效」。"
  "**标准化复制**：把跑通的 SOP + 工具配置 + 话术库打包成「可复制模板」，向新门店 / 新品类 / 新团队复制。"
  "**持续迭代**：定期复盘体系级数据，按漏斗逐环优化、淘汰无效动作。"
)
declare -a FAILURE_MODES=(
  "**私域绑死在一个人身上**: 触发原因 = 没拆组织、没标准化 SOP。怎么避免 = 早做角色拆分 + SOP 文档化，让私域是「体系」不是「某个人」。"
  "**GMV 归因口径放水 / 说不清**: 触发原因 = 没有统一归因体系，或刻意注水。怎么避免 = 统一口径 + 用留存复购交叉验证 + 对内诚实核算（intake warnings 点名）。"
  "**CLI 化暗示 (v0.6+)**: Let one operator run the entire private-domain stack with no documented SOPs — when they quit, the whole system collapses overnight. 尽早拆角色、SOP 文档化。"
  "**CLI 化暗示 (v0.6+)**: Report private-domain GMV with a loose/inflated attribution rule to look good — get the budget cut when leadership stops trusting the number. 统一归因口径并用留存/复购交叉验证。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "10-100-walkthrough"
fi
